const fs = require('fs');
const articles = JSON.parse(fs.readFileSync('app/pages/article/articles.json', 'utf8'));

// ===== article-001 =====
articles[0].translations.en = {
  title: "Reform of Equity Transfer Responsibility: Reconstruction of the Original Shareholders' Liability Boundary under the Old and New Company Laws",
  lead: "With the formal implementation of the new Company Law on July 1, 2024, the issue of liability for shareholders after transferring their equity within the term of capital contribution has become the focus of practice. By comparing the old and new legal systems and combining the latest judicial interpretations of the Supreme People's Court, this article systematically combs the liability boundaries of the original shareholders in corporate debts, and provides a reference path for creditors and shareholders to safeguard their rights.",
  meta: { date: "2024-03-15", author: "Qingsong Law Firm" },
  blocks: [
    { type: "h2", text: "Comparative Analysis of the Liability System of the New and Old Company Laws" },
    { type: "h2", text: "The regulatory logic of the original Company Law and judicial interpretations" },
    { type: "law", title: "Provisions of the Supreme People's Court on Several Issues Concerning the Application of the Company Law of the People's Republic of China (III)", content: "Article 18 Where a shareholder of a limited liability company transfers his equity without performing or fully performing his obligation of capital contribution, and the transferee knows or should know about it, and the company requests the shareholder to perform his obligation of capital contribution, and the transferee shall bear joint and several liability for it, the people's court shall support it;Where a creditor of the company brings a lawsuit against the shareholder in accordance with the second paragraph of Article 13 of these Provisions and requests the above-mentioned transferee to bear joint and several liability for this, the people's court shall support it.\n If the transferee, after assuming the liability in accordance with the provisions of the preceding paragraph, claims compensation from the shareholder who has not fulfilled or has not fully fulfilled the obligation of capital contribution, the people's court shall support it.However, unless otherwise agreed upon by the parties.\n The premise for the application of this interpretation is that the shareholder transfers the equity without fulfilling or fully fulfilling the obligation of capital contribution, and the transferee shall be jointly and severally liable to the company or creditors if he knows or should know that the original shareholder has a defect in capital contribution.At the same time, the interpretation gives the transferee the right of recourse, and the transferee has the right to recover from the original shareholder after assuming the responsibility, unless otherwise agreed by both parties.The creditor or the company shall provide evidence to prove that the transferee \"knows or should know\" the defect of the original shareholder's capital contribution, otherwise it is difficult to require the transferee to assume responsibility.In practice, the court will presume the informed state of the transferee according to the relationship between the transferor and the transferee, the reasonableness of the equity transfer price and other factors." },
    { type: "h2", text: "Institutional Innovation in Article 88 of the New Company Law" },
    { type: "h4", text: "Company Law of the People's Republic of China" },
    { type: "p", text: "Article 88 Where a shareholder transfers the equity that has subscribed for the capital contribution but has not yet reached the time limit for capital contribution, the transferee shall bear the obligation to pay the capital contribution;If the transferee fails to pay the capital contribution in full and on time, the transferor shall bear supplementary liability for the capital contribution that the transferee fails to pay on time." },
    { type: "p", text: "Where a shareholder who fails to pay the capital contribution on the date of capital contribution stipulated in the articles of association or whose actual value of the non-monetary property as capital contribution is significantly lower than the subscribed capital contribution transfers its equity, the transferor and the transferee shall be jointly and severally liable within the scope of insufficient capital contribution;If the transferee does not know and should not know that the above circumstances exist, the transferor shall be liable." },
    { type: "law", title: "The legislative basis of the first paragraph of Article 88 of the Company Law is the addition of debts. After the transfer of the equity that has not been contributed, the original shareholder shall still bear supplementary liability for the capital contribution that the transferee has not paid on time.", content: "Paragraph 2 of Article 88 refers to the distribution of capital contribution liability for the transfer of defective equity. Under such circumstances, the transferor shall bear joint and several liability within the scope of insufficient capital contribution of the transferee, and the transferor shall be liable if the transferee is in good faith.However, if the creditor provides rebuttal evidence to prove that the transferee actually knows or should know that there is a defect in the capital contribution, the transferee shall not be exempted from liability, for example, the transfer price is obviously abnormal, far lower than the normal equity transfer price, and the transferor has no reasonable explanation for this." },
    { type: "h2", text: "Applicable scenarios for the responsibility of the original shareholders" },
    { type: "h3", text: "(1) Disputes over capital contribution liability arising from the transfer of equity by shareholders before the expiration of the capital contribution period before July 1, 2024" },
    { type: "viewpoint", title: "Opinion 1: The original shareholder is not exempt from liability and still has the responsibility for capital contribution", content: "This view holds that although the transfer of equity within the term of subscribed capital contribution is a mutual agreement between the two parties, which conforms to the formal requirements of the general assignment of creditor's rights and debts, the transfer of equity involves the capital adequacy of the company. The shareholder's commitment to and obligation to make up capital contributions are mandatory provisions of the Company Law. The freedom of equity transfer transactions and the exercise of shareholders' term interests shall not harm the interests of the company and the company's creditors. The original shareholder's subscribed capital cannot be transferred along with the equity, and the original shareholder still needs to bear the responsibility for capital contribution." },
    { type: "case", badge: "Reference Case", caseId: "(2021) SU03 Min Zhong No. 7173", content: "(2021) SU03 Min Zhong No. 7173 Case, the court of second instance considers that although the time limit for capital contribution has not expired at the time of equity transfer, Article 18 of Judicial Interpretation III of the Company Law stipulates that \"the shareholders of a limited liability company transfer their equity before and after the expiration of the time limit for capital contribution if they fail to perform or fully perform their obligations for capital contribution\" does not distinguish between the transfer of equity before and after the expiration of the time limit for capital contribution. Therefore, whether the equity is transferred before or after the expiration of the capital contribution period, it falls within the normative intent of Article 18, and the original shareholder shall perform the obligation of capital contribution." },
    { type: "viewpoint", title: "Point 2: The original shareholder is no longer liable", content: "" },
    { type: "case", badge: "Reference Case", caseId: "(2021) Wan Min Zhong No. 427", content: "(2021) Wan Min Zhong No. 427 Case, the court of first instance took the third paragraph of Article 13 of Judicial Interpretation III of the Company Law as the judgment basis, and determined that the original shareholder shall be liable for supplementary compensation. However, the court of second instance considers that the premise of the original shareholder's liability is that the shareholder has the obligation to actually pay the capital contribution at the time of the establishment of the company, and if the shareholder transfers the equity before the expiration of the capital contribution period, the corresponding capital contribution obligations shall be deemed to be transferred together, and the original shareholder shall no longer be liable for the transferee's capital contribution obligations." },
    { type: "viewpoint", title: "Opinion 3: In principle, the original shareholder shall no longer be liable, except that it can be proved that the original shareholder maliciously infringes upon the interests of creditors", content: "" },
    { type: "case", badge: "Reference Case", caseId: "(2024) Yue 19 Min Zhong No. 853", content: "In (2024) Yue 19 Min Zhong No. 853 Civil Judgment, the court pointed out that when the shareholder transferred the equity within the term of capital contribution, the company was in normal business operation. Although it owed debts, there was no evidence to prove that the company was unable to pay off its due debts at the time of equity transfer, and the transferee was not obviously lacking the ability to pay capital contribution. Such equity transfer was a normal commercial act. Therefore, the court did not determine that the shareholder has the malice to evade the obligation of capital contribution when transferring the equity within the term of capital contribution, and thus did not order it to bear responsibility." },
    { type: "case", badge: "Reference Case", caseId: "(2020) Jing 03 Min Zhong No. 3634", content: "However, in the case of (2020) Jing 03 Min Zhong No. 3634, although the shareholder has not reached the time limit for capital contribution when transferring his equity, the shareholder knows that the company cannot pay off the due debts at the time of transfer, and the transferee obviously lacks the ability to pay capital contribution. Such equity transfer increases the risk of the paid-in registered capital of the company and affects the realization of the creditor's rights due to the company. Obviously, it is a malicious evasion of the obligation of capital contribution by means of equity transfer, and the transferor shall be liable for capital contribution according to law." },
    { type: "h3", text: "(2) Disputes over capital contribution liability arising from the transfer of equity by shareholders within the term of capital contribution after July 1, 2024" },
    { type: "h4", text: "1. Statutory circumstances under which liability must be assumed" },
    { type: "case", badge: "Reference Case", caseId: "(2024) Nei 04 Min Zhong No. 5215", content: "When a shareholder transfers the equity within the term of capital contribution, if the transferee fails to pay the capital contribution in full and on time, the original shareholder shall bear supplementary liability for the unpaid part, excluding interest. In the case of (2024) Nei 04 Min Zhong No. 5215, the court of second instance held that the debt between the creditor and the company occurred during the period when the original shareholder was a shareholder of the company, and the original shareholder transferred his equity without fully fulfilling his obligation to make capital contributions. If the company was unable to pay off its debts and enforce its final capital, the court applied for adding the original shareholder as the person subjected to execution in accordance with the law." },
    { type: "p", text: "If the original shareholder fails to pay the capital contribution in accordance with the articles of association or the non-monetary assets are significantly insufficient, even if the equity has been transferred, he shall still be jointly and severally liable with the transferee within the scope of insufficient capital contribution." },
    { type: "h4", text: "2. Possible Paths for Disclaimer" },
    { type: "p", text: "If the original shareholder can prove that the capital contribution has been paid in full or there is no defect, or that the creditor's rights are formed after the transfer of equity, the original shareholder may claim exemption based on the protection of trust interests. In addition, if the limitation of action has expired when the creditor claims the debt, the original shareholder may be exempted from liability by claiming the defense of limitation." },
    { type: "h2", text: "Suggestions on Optimizing the Protection Route of Creditors' Interests" },
    { type: "h2", text: "Litigation stage" },
    { type: "h2", text: "Thru Thru Recourse" },
    { type: "h4", text: "Bring a lawsuit against the original shareholder and the transferee at the same time (especially in the case of false capital contribution)" },
    { type: "h4", text: "Make good use of Article 35 of the Enterprise Bankruptcy Law to accelerate the maturity" },
    { type: "h2", text: "Key Points for Evidence Collection" },
    { type: "h4", text: "Access to industrial and commercial internal files to verify investment commitments" },
    { type: "h4", text: "Obtain the certificate of payment of the equity transfer price" },
    { type: "h4", text: "Collect the chain of evidence for the withdrawal of capital by the original shareholders" },
    { type: "h3", text: "(2) Execution stage" },
    { type: "h4", text: "Provisions on Several Issues Concerning the Alteration and Addition of Parties in Civil Execution" },
    { type: "p", text: "Article 19 Where the property of a company as the person subjected to execution is insufficient to pay off the debts specified in the effective legal documents, and its shareholder fails to perform its obligation of capital contribution in accordance with the law and transfers its equity, the applicant for execution may apply to the people's court for changing or adding the original shareholder or the initiator who shall bear joint and several liability for the capital contribution in accordance with the provisions of the Company Law as the person subjected to execution, and the people's court shall support it if it is liable within the scope of capital contribution not made in accordance with the law." },
    { type: "p", text: "The original shareholder shall be changed or added as the person subjected to execution, so as to make him liable within the scope of capital contribution not made according to law." }
  ],
  references: [
    "Company Law of the People's Republic of China",
    "Enterprise Bankruptcy Law of the People's Republic of China",
    "Provisions of the Supreme People's Court on Several Issues Concerning the Application of the Company Law of the People's Republic of China (III) (Revised in 2020)",
    "Provisions on Several Issues Concerning the Alteration and Addition of Parties in Civil Execution",
    "Several Provisions of the Supreme People's Court on the Time Effect of the Application of the Company Law of the People's Republic of China"
  ],
  subtitle: "— Article 88 of the Company Law",
  conclusion: "The change of the liability rules for the transfer of unexpired equity under the new Company Law has put forward new requirements for all parties. Whether the original shareholders, transferees or creditors, they should accurately grasp the changes in rules, rationally plan commercial acts and prevent legal risks. If you encounter relevant problems in practice, you are welcome to contact us, and Beijing Qingsong Law Firm will provide you with professional legal services."
};

// ===== article-002 =====
articles[1].translations.en = {
  title: "Cracking the \"Golden Cicada Deblocking\" Technique of Shareholders Using Intellectual Property Rights to Make False Capital Contributions: Legal Paths and Practical Guidelines",
  lead: "The minority shareholder makes a capital contribution of 3 million yuan with the intellectual property right of a game. However, the creditor finds that the actual value of the intellectual property right is far lower than the subscribed amount, resulting in no property for the company to enforce.",
  meta: { date: "2024-04-08", author: "Qingsong Law Firm" },
  blocks: [
    { type: "h4", text: "— The company has no property to enforce? How creditors fight back" },
    { type: "h2", text: "Background of the problem: the typical pattern of shareholders' \"empty handed white wolf\"" },
    { type: "p", text: "For a company with a registered capital of 39 million yuan, the minority shareholder shall make a capital contribution of 3 million yuan with the intellectual property right of a game. However, the creditor finds that the actual value of the intellectual property right is far lower than the subscribed amount, resulting in no property available for execution by the company, and the shareholder tries to evade liability through the \"evaluation report\". Although the creditor has won the lawsuit and added the shareholder as the person subjected to execution, the shareholder has filed a lawsuit against the execution, and the case has reached a deadlock." },
    { type: "p", text: "Core contradiction: How to prove that the intellectual property investment is untrue? How to break through the \"legality\" of the original evaluation report?" },
    { type: "h2", text: "Legal Weapons: Three Core Bases for Cracking Down on False Capital Contributions" },
    { type: "h2", text: "Statutory requirements for non-monetary capital contribution — transfer of ownership + valuation" },
    { type: "p", text: "In accordance with Articles 48 and 49 of the Company Law and Articles 9 and 10 of Judicial Interpretation III of the Company Law, shareholders may make capital contributions in kind, intellectual property rights, land use rights, equity, creditor's rights and other non-monetary property that can be valued in currency and transferred according to law, and two obligations shall be fulfilled for intellectual property rights:" },
    { type: "p", text: "✅ Change of ownership: transfer the intellectual property right to the company;" },
    { type: "p", text: "✅ Appraisal and pricing: a report shall be issued by a legal appraisal institution, and the price shall not be falsely overvalued." },
    { type: "p", text: "Legal consequences: If the transfer of ownership has not been completed or the appraisal price is significantly low, it shall be deemed that it has not fulfilled its obligation of capital contribution, and the shareholders shall make up the difference." },
    { type: "h2", text: "Joint and several liability for false capital contribution of shareholders" },
    { type: "p", text: "Paragraph 1 of Article 23 of the Company Law. Where a shareholder of a company abuses the independent status of a company as a juridical person and the limited liability of a shareholder to evade debts and seriously damages the interests of the creditors of the company, he shall bear joint and several liabilities for the debts of the company." },
    { type: "p", text: "The creditor may, in accordance with Article 50 of the Company Law or Article 13 of the Judicial Interpretation III of the Company Law, require the shareholder to assume supplementary liability for the debts of the company within the scope of the principal and interest not contributed." },
    { type: "p", text: "In addition, if a shareholder abuses his right to transfer assets or evade debts, which seriously damages the interests of the creditors of the company, the damaged creditor may, in accordance with Article 23 of the Company Law, claim that the shareholder is confused with the company's personality and require the shareholder to bear joint and several liability." },
    { type: "h2", text: "Cracking the Way: Four Steps to Break through the \"Obstruction\" of Shareholders" },
    { type: "h2", text: "Step 1: Application for Investigation Order and Property Preservation" },
    { type: "p", text: "The transfer of assets by shareholders is concealed, and creditors first need to apply for property preservation simultaneously at the litigation stage." },
    { type: "p", text: "Next, obtain the industrial and commercial internal files of the company by applying for an investigation order, focusing on the verification of intellectual property evaluation reports, intellectual property registration information, related party transaction records, ownership change records and capital verification files in the industrial and commercial archives. In this step, we can find the clues of the value of the intellectual property used by the shareholder as capital contribution and the loopholes therein, so as to prepare for the next step of applying for judicial audit." },
    { type: "case", badge: "Reference Case", caseId: "(2020) Lu 15 Min Zai No. 23", content: "If the shareholder fails to complete the change of ownership of intellectual property rights in the (2020) Case No. 23 of the 15th People's Court of Shandong Province, the court directly determines that it has not fulfilled its obligation of capital contribution and assumes supplementary liability." },
    { type: "case", badge: "Reference Case", caseId: "(2024) Jing 03 Min Zhong No. 11534", content: "In Case No. 11534 [2024] of Jing 03 Civil Division, the judge pointed out that the amount of intellectual property investment shown in the resolution of the shareholders' meeting and the amendment to the articles of association made earlier was completely consistent with the value of intellectual property in the evaluation report made later, which was obviously unreasonable; Secondly, when the shareholder changes the monetary capital contribution into a patent during the debt crisis, the court ruled that the act would not have the legal effect of capital contribution on the grounds that the act reduced the liquidity of property and objectively damaged the interests of creditors." },
    { type: "case", badge: "Reference Case", caseId: "(2023) Yu 0107 Zhiyi No. 311", content: "In the case of (2023) Yu 0107 Zhiyi No. 311, the court held that when judging whether a shareholder has fulfilled the capital contribution of non-patented technology, it should also examine the relevance of the non-patented technology to the business purpose of the company to prevent shareholders from \"spending money to buy packages\", making capital contributions at a price of false non-patented technology, and covering up untrue capital contributions in legal form. This can also be used as an important basis for judging whether shareholders make false capital contributions by using intellectual property rights." },
    { type: "h2", text: "Step 2: Apply for Judicial Audit and Peel the Veil of False Assessment" },
    { type: "law", title: "Provisions of the Supreme People's Court on Several Issues Concerning Property Investigation in Civil Execution (2020 Amendment)", content: "Article 17 If a juridical person or unincorporated organization as the person subjected to execution fails to perform the obligations specified in the effective legal documents, and the applicant for execution considers that it has evaded its debts by refusing to report, falsely reporting its property, concealing or transferring its property, or that its shareholders or investors have made false capital contributions or withdrawn their capital contributions, it may apply in writing to the people's court for entrusting an audit institution to audit the person subjected to execution. The people's court shall decide whether to grant or not within ten days from the date of receipt of the written application." },
    { type: "h2", text: "Practical Difficulties and Cracking Skills" },
    { type: "p", text: "Difficulty 1: How can the judge be persuaded to initiate a reassessment?" },
    { type: "p", text: "Obtain clues such as intellectual property appraisal reports, ownership change records and capital verification files by applying for investigation orders to find out possible defects in the capital contribution, such as:" },
    { type: "p", text: "Creditors may prove that the actual value of intellectual property rights differs greatly from the amount subscribed by comparing the transaction price, actual income data and cost price of obtaining intellectual property rights of the same kind in the market;" },
    { type: "p", text: "If the intellectual property is not actually delivered for use (such as the game is not online for operation) or the intellectual property has no relevance to the business purpose of the company, it may be claimed that the capital contribution has not been completed accordingly;" },
    { type: "p", text: "Provide the \"black history\" of the original assessment institution (such as administrative penalty records), directly claim that the original report is not trustworthy, and request a new assessment;" },
    { type: "p", text: "If the evaluation report of the intellectual property right does not disclose the key restrictions and the evaluation parameters are unreasonable, it may be claimed that the evaluation procedure is illegal;" },
    { type: "p", text: "Difficulty 2: How to deal with the shareholder's claim that \"market fluctuations lead to depreciation\"?" },
    { type: "p", text: "If the shareholder claims the depreciation caused by market changes in accordance with Article 15 of Judicial Interpretation III of the Company Law, the shareholder does not need to make up for it, and indicates that the depreciation is not caused by subjective malice." },
    { type: "p", text: "Creditors may deny the \"market fluctuation\" defense by proving that intellectual property rights do not have high value from the beginning (such as outdated technology and no practical application scenario)." },
    { type: "h2", text: "Step 3: The application for declaring the shareholder's change in the mode of capital contribution invalid and recovering the transferred assets" },
    { type: "p", text: "After the company's debts arise, and the company's creditors have already requested the shareholders to accelerate the expiration of their capital contributions through litigation, if the shareholders change the mode of capital contribution through a shareholders' resolution to evade the obligation of monetary capital contribution, it is an act of abusing shareholders' rights to harm the interests of the company's creditors, which is prohibited by the Company Law. However, the Company Law does not explicitly stipulate the legal effect of such acts. Paragraph 3 of Article 3 of the Interpretation of the Supreme People's Court on Several Issues Concerning the Application of the General Principles of the Civil Code of the People's Republic of China stipulates that if an abuse of civil rights is constituted, the people's court shall determine that the abuse does not have corresponding legal effect." },
    { type: "case", badge: "Reference Case", caseId: "(2024) Jing Min Zhong No. 3", content: "In (2024) Jing Min Zhong No. 3, when the company's debts cannot be paid off to the outside world, the shareholders change the monetary capital contribution into non-monetary intellectual property capital contribution. As the Company Law stipulates that the mode of capital contribution is publicity, the creditor decides whether to trade with the company according to the publicity information, and the creditor has a trust interest in the mode of capital contribution. Non-monetary capital contribution, especially intellectual property capital contribution, is obviously limited in its solvency compared with monetary capital contribution. Therefore, if the shareholder changes the capital contribution after the debt occurs, it shall not be binding on the creditor, and the creditor shall still have the right to request the shareholder to continue to make monetary capital contribution." }
  ],
  references: [],
  subtitle: "",
  conclusion: "The \"legal cloak\" of shareholders who make false capital contributions by using intellectual property rights will eventually be broken down by law! Creditors should make good use of such tools as judicial audit, additional executors and revocation litigation to form a high-pressure situation in combination with criminal accountability. Only professional layout + rapid action can solve the implementation deadlock and realize the collection of creditor's rights."
};

// ===== article-003 =====
articles[2].translations.en = {
  title: "Interpretation of the Implementation Practice of Real Estate Registration and Concealment: Four Scenes and Legal Paths to Pierce the Veil",
  lead: "Real estate registered in the name of others is definitely not a \"debt avoidance safe\"! Creditors only need to grasp the three cores of the source of capital contribution, actual control and debt time line, and cooperate with the flexible use of legal tools, they can negate the effect of registration facade through legal procedures, so that hidden property has no hiding place.",
  meta: { date: "2024-05-22", author: "Qingsong Law Firm" },
  blocks: [
    { type: "h4", text: "Introduction" },
    { type: "p", text: "In the civil execution procedure, some persons subjected to execution, in order to evade their debts, register the purchase of real estate actually funded by themselves in the name of their spouses, children or even other third parties, resulting in \"no property available for execution\" when the court executes it - a common phenomenon. However, the real estate registration is not equal to the real ownership! This article, based on the Civil Code and judicial interpretations and supported by judicial precedents, dismantles the four scenarios of \"concealing property by name\" and the ways to solve them, so as to provide creditors with a penetrating execution plan." },
    { type: "h2", text: "Four Hidden Scenes and Cracking Paths" },
    { type: "p", text: "Scenario 1: Real Estate Registered in Spouse's Name – Subdivision of Common Property by Subrogation & Cancellation of Improper Disposal" },
    { type: "p", text: "Can the property registered in the name of the spouse be directly executed if the person subjected to execution divides his or her real estate or the real estate belonging to the common property of the husband and wife by means of divorce agreement?" },
    { type: "p", text: "If the property is registered in the name of the spouse, but there is direct evidence to prove that it is the joint property of the husband and wife, according to Article 12 of the Provisions of the Supreme People's Court on Sealing up, Seizure and Freezing Property in Civil Execution by the People's Court, the court may directly seal up the jointly owned property and notify the co-owners in a timely manner. The co-owners may agree to divide the property or bring a lawsuit against the co-owners for property division. If the co-owners are lazy in dividing the property and cause damage to the rights and interests of the creditors, the creditors may directly bring a lawsuit against the creditors for property division on their behalf." },
    { type: "p", text: "If the spouse claims personal property, the creditor may bring a lawsuit of property division by subrogation to confirm the debtor's share of property. If the person subjected to execution transfers his property free of charge through a divorce agreement, the creditor may bring an action for cancellation right." },
    { type: "case", badge: "Reference Case", caseId: "(2024) Yun 01 Min Zhong No. 959", content: "In case No. 959 [2024] of Yun01 Civil Division, the court held that after the debt was incurred, the debtor's gratuitous disposal of the house involved in the case through the divorce agreement had affected the realization of the creditor's rights, and the agreement seriously weakened the debtor's ability to pay off, so the court supported the claim to revoke the case involving the second paragraph of Article 5 \"Property Division\" of the Divorce Agreement." },
    { type: "p", text: "Scene 2: Real Estate Registered in the Name of a Third Person – Revocation Action" },
    { type: "p", text: "If the person subjected to execution has a high solvency at the time of signing the contract for debts, the creditor decides to trade with the person subjected to execution only on the basis of the better goodwill of the person subjected to execution. However, after the creditor's rights and debts are incurred, if the person subjected to execution donates property or transfers it to others at an unreasonable low price, his solvency will be reduced, and the gratuitous donation will damage the interests of the creditor. Therefore, the creditor may bring a lawsuit to revoke the donation or transfer." },
    { type: "case", badge: "Reference Case", caseId: "(2021) Yu 05 Min Zhong No. 888", content: "In the case of (2021) Yu 05 Min Zhong No. 888, the debtor transferred the house in dispute to a third party at an obviously unreasonable low price after the debt occurred, thus harming the realization of the interests of the creditor, so the court supported the creditor's claim to revoke the House Sale Agreement signed by the defendant and the third party, and confirmed that the real estate involved in the case was owned by the debtor." },
    { type: "p", text: "However, on the contrary, if the person subjected to execution had already donated the property to others before signing the contract for debts, since the creditor had examined the goodwill of the person subjected to execution and still decided to have business dealings with him when signing the contract for debts, this is a failure of the creditor to fulfill his duty of prudence, and the creditor should bear the transaction risk himself and shall not revoke the donation of the person subjected to execution." },
    { type: "p", text: "Scene 3: Real estate registered in the name of minor children - confirmation action is recognized as family common property" },
    { type: "h2", text: "First of all, generally speaking, minor children have no income and the purchase money generally comes from their parents." },
    { type: "p", text: "The People's Court of Yunyang County considers that according to Article 595 of the Civil Code, \"a sales contract is a contract whereby the seller transfers the ownership of the subject matter to the buyer and the buyer pays the price\". According to the purchase contract and relevant payment receipts and other evidence, if the price of the purchase subject matter is actually paid, it shall be the actual buyer of the sales contract." },
    { type: "p", text: "If the purchase price is paid by the child, examine whether the child has the actual purchasing power. If a minor child has no independent source of income and basically has no purchasing power, the nature of the property under the minor child's name should be emphasized. As a member of the family, the property under the name of a minor child, regardless of whether it comes from either party of the husband and wife, generally belongs to the common property of the family. However, it does not rule out that some minor children do enjoy personal property. From the perspective of protecting the legitimate rights and interests of creditors and safeguarding the safety of transactions, such property should undoubtedly be recognized as owned by minor children, and the court shall not list such property as the scope of execution when handling enforcement cases, nor shall it take compulsory measures such as freezing and sealing up." },
    { type: "p", text: "Secondly, although the house is registered under the name of the minor child, most of the houses are shared by family members for a long time, and the real estate managed by the parents shall be regarded as the common property of the family." },
    { type: "case", badge: "Reference Case", caseId: "(2022) Xiang 0725 Min Chu No. 3288", content: "In the case No. 3288 [2022] of the early Republic of China of Xiang 0725, the court took the existing use status of the house as one of the bases for judging the actual ownership of the house." },
    { type: "p", text: "The time of final real estate registration and the time before and after the formation of the debt is an important factor in examining whether the debtor is malicious, and also an important basis for the creditor to exercise the right of revocation." },
    { type: "p", text: "If the real estate is registered after the debt, according to the provisions of Article 154 of the Civil Code: \"A civil juristic act of malicious collusion between the actor and the counterpart that damages the legitimate rights and interests of others is invalid.\" Malicious transfer may be directly presumed; The applicant for execution may revoke the gift through the creditor's action for revocation to make the above-mentioned house return to the owner of the executed person, and then execute the above-mentioned house." },
    { type: "case", badge: "Reference Case", caseId: "(2022) Xiang 0725 Min Chu No. 3288", content: "If the real estate is registered before the debt occurs, the Civil Ruling No. (2020) of the Supreme People's Court holds that the house registered in the name of the minor child purchased by the person subjected to execution is the common property of the family, and the shares owned by the person subjected to execution may be executed. The People's Court of Taoyuan County, Hunan Province, in Case No. 3288 [2022] of the early Republic of China, held that there was no sufficient evidence to prove that the debtor's husband and wife really meant to donate the house to their minor daughter when purchasing the house; In addition, if his minor daughter has not provided evidence to prove that he has invested or contributed to the house involved in the case, the court shall determine that the house is the joint property of the debtor's husband and wife from the perspective of balancing the interests of both creditors and debtors in light of the actual investment, existing use status and social status of the house involved in the case." },
    { type: "p", text: "Scene 4: Real estate is registered in the name of an adult child - the action for confirmation is recognized as the common property of the family" },
    { type: "p", text: "Adult children need to prove their ability to purchase houses by themselves, otherwise they may still be recognized as holding on their behalf! Whether the purchase money comes from the debtor is an important basis for judging the actual ownership of the house. For adult children, we should focus on examining whether their wage income level is positively related to the property involved, such as large transfer and property status before the formation of debts." },
    { type: "p", text: "(2020) In the Supreme People's Court Case No. 5648, the Supreme People's Court held that the children of the person subjected to execution did not have the corresponding ability to pay the purchase price when purchasing the house, and the money involved in the case was paid by the person subjected to execution. However, when the children of the person subjected to execution purchased the house involved in the case, the creditor's rights and debts between the creditor and the person subjected to execution did not occur, and it cannot be proved that the purchase of a house for the children of the person subjected to execution was a malicious evasion of debts. The house involved in the case is purchased by the debtor's husband and wife, and his adult daughter has no financial ability to purchase a house with a value of nearly one million yuan when purchasing the house. The actual investor of the house involved in the case is not the right registrant. Therefore, the court determines that the house involved in the case is the common property of the debtor's husband and wife and their adult daughter's family, and the shares owned by the person subjected to execution may be executed." },
    { type: "h2", text: "Lawyers' Case Handling Tool Box: Guidelines for the Whole Process of Enforcement Procedures" },
    { type: "h2", text: "Property clues mining and evidence chain construction" },
    { type: "p", text: "Application for investigation order: obtain the bank flow, house purchase contract, real estate registration information and property records of the debtor and related parties; Find out the certificate of capital contribution for the purchase price and the certificate of actual possession and use." },
    { type: "h2", text: "Through the flow of funds: According to the debtor's property report, focus on the verification of abnormal transfers before and after the formation of debts." },
    { type: "h2", text: "Litigation Strategy Selection" },
    { type: "h2", text: "Revocation right action: against gratuitous transfer or malicious transfer" },
    { type: "case", badge: "Reference Case", caseId: "(2023) Yu 0231 Min Chu No. 2731", content: "In Case No. 2731 [2023] of the Early Republic of China, the debtor attempted to dispose of the house involved in the case free of charge by signing the Divorce Agreement, which seriously damaged the legitimate rights and interests of the creditor, and the court supported the creditor's claim to revoke the debtor's agreement through the divorce agreement." },
    { type: "h2", text: "Subrogation of property division litigation: against the common property of husband, wife and family, and the debtor is negligent in dividing the property" },
    { type: "case", badge: "Reference Case", caseId: "(2024) Shaan 0111 Min Chu No. 5035", content: "In the (2024) Shaan 0111 Early Republic of China Case No. 5035 and (2025) Yun 01 Civil End Case No. 518, the relevant creditor's rights are in the compulsory execution of the court, and the debtor has no other property available for execution except for the property shared with an outsider. The court has sealed up, seized or frozen the common property and notified the co-owners. The person subjected to execution and other co-owners neither agree to divide the common property nor bring a lawsuit for property division, which hinders the compulsory execution of the court and the realization of the creditor's rights of the applicant for execution. The court supports the creditor's claim for property division, and safeguards the legitimate rights and interests of the creditor." },
    { type: "h2", text: "Use the \"crime of refusing to execute\" flexibly to exert pressure: those whose malicious transfer is serious shall be investigated for criminal responsibility" },
    { type: "case", badge: "Reference Case", caseId: "(2025) Xin 40 Xing Zhong No. 9", content: "In (2025) Xin 40 Xing Zhong No. 9 Case, the court held that the defendant Chen Jiajia, in order to evade responsibility, after receiving the notice from the court adding him as the person subjected to execution, knew that his real estate had bank loans unpaid and his property was insufficient to pay off the debts to the applicant for execution, Yang Yi, still sold the real estate, and required the buyer to pay the sale price in cash to his son, transferring and concealing property to evade the execution of the court. The subjective intention to evade the execution of the court was obvious, resulting in the effective ruling of the people's court being unable to be executed, which is a serious circumstance, and has constituted the crime of refusing to execute the judgment or ruling, and shall be punished according to law." },
    { type: "h2", text: "Implementation of interface measures" },
    { type: "p", text: "In accordance with the provisions of the first and second paragraphs of Article 13 of the Provisions of the Supreme People's Court on Sealing up, Seizure and Freezing Property in Civil Execution by People's Courts, the real estate under the name of a third party shall be applied for sealing up synchronously to prevent sale; To apply for execution directly with an effective judgment to avoid idling of the procedure." }
  ],
  references: [],
  subtitle: "",
  conclusion: "Real estate registered in the name of others is definitely not a \"safe for avoiding debts\"! Creditors only need to grasp the three cores of the source of capital contribution, actual control and debt time line, and cooperate with the flexible use of legal tools, they can negate the validity of registration facade through legal procedures, so that hidden property has nothing to hide!\n(All parties to the case in the text are pseudonyms, please contact a professional enforcement lawyer if you need case consultation)\n— We have been focusing on the field of enforcement for 10 years, and we have made the judgment sound —\nReference:\nCivil Code of the People's Republic of China\nArticle 154 Civil juristic acts in which the actor and the counterpart collude maliciously and damage the legitimate rights and interests of others are invalid.\nArticle 303 Where the co-owners agree not to divide a commonly owned realty or chattel in order to maintain the relationship of co-ownership, the agreement shall be followed, provided that if the co-owners have major reasons to divide the realty or chattel, they may request the division; If there is no agreement or the agreement is not clear, the co-owners by shares may request the division at any time, and the co-owners may request the division when the common basis is lost or there are major reasons for the division. If the division causes damage to other co-owners, compensation shall be made.\nArticle 538 Where a debtor disposes of its property rights and interests free of charge by waiving its creditor's rights, waiving the guarantee of its creditor's rights, or transferring its property free of charge, or maliciously extends the time limit for the performance of its due creditor's rights, thus affecting the realization of the creditor's rights, the creditor may request the people's court to revoke the debtor's act.\nArticle 541 The obligee's cancellation right shall be exercised within one year from the date when the obligee knows or should know the reason for cancellation. If the cancellation right is not exercised within five years from the date of the debtor's act, the cancellation right shall be extinguished.\nCriminal Law of the People's Republic of China\nArticle 313 [Crime of Refusing to Execute Judgment or Ruling] Whoever has the ability to execute the judgment or ruling of the people's court but refuses to do so, and the circumstances are serious, shall be sentenced to fixed-term imprisonment of not more than three years, criminal detention or a fine; if the circumstances are especially serious, he shall be sentenced to fixed-term imprisonment of not less than three years but not more than seven years, and shall also be fined.\nProvisions of the Supreme People's Court on Sealing up, Seizure and Freezing Property in Civil Execution by People's Courts\nArticle 12 The people's court may seal up, seize or freeze the property jointly owned by the person subjected to execution and others, and shall notify the co-owners in a timely manner.\nThe co-owners may agree to divide the jointly owned property, and if the creditor recognizes it, the people's court may determine that it is valid. The effect of sealing up, seizing or freezing shall extend to the property within the share enjoyed by the person subjected to execution after the division of the property by agreement; For the property within the share enjoyed by other co-owners, the people's court shall rule to release the sealing up, seizure or freezing.\nIf the co-owners bring a lawsuit for property division or the applicant for execution brings a lawsuit for property division by subrogation, the people's court shall permit it. The execution of the property shall be suspended during the litigation period.\nArticle 13 Paragraphs 1 and 2 The people's court may seal up, seize or freeze the property of the person subjected to execution possessed by a third party for the benefit of the person subjected to execution; If the property is designated to be kept by a third party, the third party shall not deliver it to the person subjected to execution.\nFor the property of the person subjected to execution possessed by a third party for his own interest according to law, the people's court may seal up, seize or freeze it, and the third party may continue to possess and use the property, but shall not deliver it to the person subjected to execution.\n(2020) Zui Gao Fa Min Shen No. 6800\n(2020) Zui Gao Fa Min Shen No. 5648\n(2021) Yu 05 Min Zhong No. 888\n(2022) Xiang 0725 Min Chu No. 3288\n(2023) Yu 0231 Min Chu No. 2731\n(2024) Yun 01 Min Zhong No. 959\n(2025) Xin 40 Xing Zhong No. 9"
};

// ===== article-004 =====
articles[3].translations.en = {
  title: "Case sharing: Can the execution be ruled out if an outsider wrongly transfers funds to the account of the person subjected to execution?",
  lead: "In the civil execution procedure, it is not uncommon for an outsider to transfer funds to the account of the person subjected to execution due to operational errors in the execution procedure. The focus of such disputes is: whether the \"wrongly transferred\" money belongs to the property of the person subjected to execution? Can an outsider rule out enforcement through the enforcement objection procedure? This article analyzes the legal rules and practical essentials of such cases in light of a successful collection enforcement case represented by our lawyers.",
  meta: { date: "2024-06-10", author: "Qingsong Law Firm" },
  blocks: [
    { type: "h2", text: "Brief introduction to the case: the payment for goods of 500000 yuan was wrongly transferred to the account of the person subjected to execution, and the objection of the outsider was rejected" },
    { type: "p", text: "In the case of a dispute over a sales contract between Mr. Wang and Mr. Shi, Mr. Shi failed to perform the payment obligation specified in the effective legal document, so Mr. Wang entrusted the lawyer of the firm to file an application for enforcement on his behalf." },
    { type: "p", text: "In the course of execution, the deposit account of a bank under the name of Shi was frozen by the court. The outsiders, Zhan and Chen, need to pay for the goods due to their business dealings with Shi Xiaomou, Shi's son. In January 2025, Zhan entrusted his wife, Chen, to transfer 500000 yuan to Shi Xiaomou's account. Therefore, Chen transferred 500000 yuan to Shi's account with a postscript of \"Ganoderm Powder\", intending to let Shi collect money on behalf of Shi Xiaomou. Due to the freezing of Shi's account, the funds cannot be transferred out, and the transaction is suspended. Zhan and Chen raised an objection to the execution to the court on the grounds of wrong transfer and requested the original route to refund 500000 yuan." },
    { type: "p", text: "Focus of dispute:" },
    { type: "h2", text: "Does the amount transferred by mistake still belong to the property of Shi?" },
    { type: "h2", text: "Can an outsider rule out enforcement on the grounds of \"wrongful transfer\"?" },
    { type: "h2", text: "Lawyers hit the nail on the head: from the ownership of currency to the rules of evidence, the three defenses build a strong line of defense for enforcement" },
    { type: "p", text: "The \"possession is ownership\" rule of money - the ownership of the money involved has been transferred and belongs to the enforceable property of Shi of the person subjected to execution." },
    { type: "p", text: "According to Item (3) of Paragraph 1 of Article 25 of the Provisions of the Supreme People's Court on Several Issues Concerning the Handling of Cases of Objection to Execution and Reconsideration by People's Courts, the ownership of bank deposits shall be subject to the registered name of the account. As a kind of thing, currency follows the principle of \"possession is ownership\", and once transferred to the account of the person subjected to execution, it shall be regarded as its responsible property, which can be executed by the court according to law." },
    { type: "h2", text: "The burden of proof for the act of wrongful transfer - the evidence provided by the outsiders, Mr. and Mrs. Zhan and Mr. Chen, is insufficient to prove that the transfer is wrongful" },
    { type: "p", text: "Chen clearly knows that the transfer account is owned by Shi, and the bank account transaction records provided by him can only prove that there is a transfer, but cannot prove that it is a transfer by mistake. Chen, knowing that the payee is Shi but still chooses to transfer, claims that the transfer is a \"transfer by mistake\", which does not conform to the common sense, and the nature of collection is not specified in the postscript of the transfer, \"Ganoderm Powder\". Therefore, 500000 yuan involved in the case belongs to Shi, which is an enforceable property." },
    { type: "h2", text: "The core of the judgment of the court: Why can the claim of \"wrongful transfer\" not prevent the execution?" },
    { type: "p", text: "The court considers that Item 3 of Paragraph 1 of Article 25 of the Provisions of the Supreme People's Court on Several Issues Concerning the Handling of Cases of Objection to Execution and Reconsideration by People's Courts stipulates that \"If an outsider raises an objection to the execution of a bank deposit enforced by the people's court, the people's court shall judge whether the objector to execution is the obligee according to the account name registered by the financial institution.\" In this case, Shi, the person subjected to execution, has an enforcement case that has not been completed, and the court's freezing of the deposit account of Shi, the person subjected to execution, conforms to the provisions of law. For the payment of 500000 yuan remitted into the deposit account of Shi, the person subjected to execution, as mentioned by the outsiders, Zhan and Chen, before the transfer, they know that the remitted account is the bank account under the name of the person subjected to execution, and the act does not belong to wrong remittance or wrong remittance. The court shall not support their claim that the payment belongs to them without legal basis. On this basis, the court rejected the objection request of outsiders Zhan and Chen." },
    { type: "p", text: "Execution effect: Eventually, all the 500000 yuan of payment for goods will be used for execution, and Mr. Wang's creditor's rights will be realized in full! The case was closed in February 2025." },
    { type: "h2", text: "Practice Guide for Lawyers: How to Prevent the Risk of Mistransfer? How should we deal with objections to enforcement?" },
    { type: "h2", text: "Relief route for transfer of funds by mistake" },
    { type: "h2", text: "Execution of Objection Procedure" },
    { type: "p", text: "This procedure is only applicable to outsiders who enjoy real rights or special creditor's rights over the subject matter of execution. As the funds in this case have been mixed with other funds after entering the account of Shi, they are not specific and cannot return the \"original object\" in fact, and have no right to claim the \"original object return\". Execution of ordinary claims (such as unjust enrichment in the case) cannot be excluded." },
    { type: "h2", text: "Claim of unjust enrichment in a separate action" },
    { type: "p", text: "According to the provisions of Article 14 of the Interpretation of the Supreme People's Court on Several Issues Concerning the Application of Enforcement Procedures, Zhan and Chen are unable to request the exclusion of compulsory execution on the basis of property rights on the grounds of claims for wrongful transfer of claims for unjust enrichment." },
    { type: "p", text: "An outsider may bring a suit against the person subjected to execution in another case to demand the return of money, but he shall be compensated equally with other creditors without priority." },
    { type: "h2", text: "Special circumstances break through the possibility of \"possession is ownership\"" },
    { type: "p", text: "If the transfer by mistake meets the following conditions, the outsider may exclude the execution:" },
    { type: "h2", text: "Special accounts for special funds: such as special accounts for migrant workers' wages and deposit accounts, etc. The funds have specific purposes and are not confused;" },
    { type: "h2", text: "Account is specified: the money is not used after entering the account and is distinguished from other funds of the person subjected to execution;" },
    { type: "p", text: "Clear collection agreement: the outsider and the person subjected to execution sign a collection agreement, and the third party (the actual payee) confirms the fact of collection." },
    { type: "h2", text: "Risk prevention suggestions" },
    { type: "p", text: "Double confirmation before transfer: check the account name, account number and opening bank to avoid blind transfer only based on \"kinship\" or \"historical transaction\"." },
    { type: "p", text: "Remarks specify the purpose: If it is collected and paid on behalf of others, it shall indicate \"collect on behalf of XX\" in the postscript of the transfer, and keep written agreements, chat records and other evidence." },
    { type: "h2", text: "Timely take preservation measures: immediately report to the police and apply for account freezing after discovering the wrong transfer to prevent the funds from being deducted." }
  ],
  references: [
    "Civil Code of the People's Republic of China",
    "Civil Procedure Law of the People's Republic of China",
    "Interpretation of the Supreme People's Court on Several Issues Concerning the Application of the Enforcement Procedure of the Civil Procedure Law of the People's Republic of China",
    "Provisions of the Supreme People's Court on Several Issues Concerning the Handling of Cases of Objection to Execution and Reconsideration by People's Courts"
  ],
  subtitle: "",
  conclusion: "Whether the transfer of funds by mistake can exclude the execution lies in the determination of the ownership of funds and the nature of the rights of outsiders. The \"possession is ownership\" rule of currency is universal, and it is difficult for outsiders to support the exclusion of execution only by claiming \"wrongful transfer\". Enterprises and individuals should attach importance to account compliance management in transactions, seek professional legal assistance in a timely manner in case of disputes, and safeguard their rights and interests through accurate legal strategies.\nFollow us for more practical guidelines on enforcement objections and remedies!\n(The cases and viewpoints in this article are for practical reference, and the specific cases need to be analyzed in combination with the rules of the competent court.)"
};

fs.writeFileSync('app/pages/article/articles.json', JSON.stringify(articles, null, 2));
